+            wake_pending: task.wake_pending,
+            obligations,
+            waiters,
+        }
+    }
+}
+
+fn duration_to_nanos(duration: Duration) -> u64 {
+    duration.as_nanos().min(u128::from(u64::MAX)) as u64
+}
+
+fn phase_name(phase: TaskPhase) -> &'static str {
+    match phase {
