+        TaskPhase::Running => "Running",
+        TaskPhase::CancelRequested => "CancelRequested",
+        TaskPhase::Cancelling => "Cancelling",
+        TaskPhase::Finalizing => "Finalizing",
+        TaskPhase::Completed => "Completed",
+    }
+}
